                        let i = 0;
                        const el = document.getElementById('dynamic-msg');
                        setInterval(() => {
                            el.parentElement.style.opacity = 0;
                            setTimeout(() => {
                                i = (i + 1) % msgs.length;
                                el.innerText = msgs[i];
                                el.parentElement.style.opacity = 1;
                            }, 500);
                        }, 2500);
